import './main2.css';
import { motion } from 'framer-motion';

const Main = () => {
  return (
    <motion.div
      variants={{
        hidden: { opacity: 0, y: 50 },
        visible: { opacity: 1, y: 0 },
      }}
      initial="hidden"
      animate="visible"
      transition={{
        duration: 0.6,
        delay: 0.2,
      }}
      className="Main"
      id="mainy"
    >
      <div className="main_left">
        <h2 className="names">About Me</h2>
        <p className="i_am_a">
          I'm <strong>Sanmathi S</strong>, a passionate developer and technology enthusiast.
          With a strong interest in web development, coding competitions, and problem-solving, I aim to create meaningful digital experiences.
        </p>
        <p className="i_am_a">
          Currently pursuing my M.Sc., I'm actively involved in coding communities and enjoy building applications that solve real-world problems. I also take part in organizing and mentoring in tech events and hackathons.
        </p>
        <p className="i_am_a">
          When I’m not coding, I enjoy reading about new technologies, contributing to open-source, and mentoring fellow developers.
        </p>
        <div className="flex1">
          <a href="mailto:vamsipraneeth2004@gmail.com">
            <button className="buttonc">Contact Me</button>
          </a>
        </div>
      </div>

      <div className="right_main">
        <img
          className="behind_the_image"
          src="data:image/svg+xml;utf8,%3Csvg viewBox=%220 0 1000 1000%22 xmlns=%22http:%2F%2Fwww.w3.org%2F2000%2Fsvg%22%3E%3Cdefs%3E%3ClinearGradient id=%22b%22 gradientTransform=%22rotate(-45 .5 .5)%22%3E%3Cstop offset=%220%25%22 stop-color=%22%2300cefc%22%2F%3E%3Cstop offset=%22100%25%22 stop-color=%22%233c1d4b%22%2F%3E%3C%2FlinearGradient%3E%3CclipPath id=%22a%22%3E%3Cpath fill=%22currentColor%22 d=%22M921 673.5q-74 173.5-247.5 191t-347 0Q153 847 86.5 673.5T130 370q110-130 240-234.5t281-21Q802 198 898.5 349T921 673.5Z%22%2F%3E%3C%2FclipPath%3E%3C%2Fdefs%3E%3Cg clip-path=%22url(%23a)%22%3E%3Cpath fill=%22url(%23b)%22 d=%22M921 673.5q-74 173.5-247.5 191t-347 0Q153 847 86.5 673.5T130 370q110-130 240-234.5t281-21Q802 198 898.5 349T921 673.5Z%22%2F%3E%3C%2Fg%3E%3C%2Fsvg%3E"
          alt=""
        />
      </div>
    </motion.div>
  );
};

export default Main;
